#include<stdio.h>

int main(){
	int gleft,gright,bleft,bright;
	int flag=0;
	scanf("%d %d",&gleft,&gright);
	scanf("%d %d",&bleft,&bright);

	if(bleft==1 && gright==1)flag=1;
	else if(gleft==1 && bright==1)flag=1;
	else if(gleft*2+3>bright && gleft <=bright+1)flag=1;
	else if(gright*2+3>bleft && gright <=bleft+1)flag=1;

	if(flag==1)printf("YES\n");
	else printf("NO\n");
	return 0;
	}

